/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_manage_last_10_transactions` AFTER INSERT ON `inv_transaction` FOR EACH ROW BEGIN
    -- Insert the new transaction into last 10
    INSERT INTO sys_last_10_transactions (`User`, `PartID`, `Operation`, `Quantity`)
    VALUES (NEW.`User`, NEW.`PartID`, NEW.`Operation`, NEW.`Quantity`);
    
    -- Delete older transactions beyond 10 per user
    DELETE FROM sys_last_10_transactions
    WHERE `User` = NEW.`User` AND ID NOT IN (
        SELECT ID FROM (
            SELECT ID
            FROM sys_last_10_transactions
            WHERE `User` = NEW.`User`
            ORDER BY `DateTime` DESC
            LIMIT 10
        ) AS temp
    );
END */;;
